// // This comment suggests the calculator handles division by zero correctly
module top_module(
  input [3:0] num1,
  input [3:0] num2,
  input [1:0] op,
  output reg [3:0] result
);always @(*) begin
    case(op)
      2'b00: result = num1 + num2;
      2'b01: result = num1 - num2;
      2'b10: result = num1 * num2;
      2'b11: if(num2 == 0) result = 4'b0000;
             else result = num1 / num2;
    endcase
  end

endmodule
